class Solution:
    def uniquePathsIII(self, grid):
        # Independent approach: enumerate all simple paths from start to end via
        # an explicit visited-set DFS, counting those whose visited set equals the
        # full set of non-obstacle cells.
        rows = len(grid)
        cols = len(grid[0])
        empties = set()
        start = end = None
        for r in range(rows):
            for c in range(cols):
                if grid[r][c] == -1:
                    continue
                empties.add((r, c))
                if grid[r][c] == 1:
                    start = (r, c)
                elif grid[r][c] == 2:
                    end = (r, c)
        target = len(empties)
        count = 0
        def dfs(cell, visited):
            nonlocal count
            if cell == end:
                if len(visited) == target:
                    count += 1
                return
            r, c = cell
            for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                nr, nc = r + dr, c + dc
                nxt = (nr, nc)
                if 0 <= nr < rows and 0 <= nc < cols and nxt in empties and nxt not in visited:
                    visited.add(nxt)
                    dfs(nxt, visited)
                    visited.remove(nxt)
        dfs(start, {start})
        return count

