class Solution:
    def uniquePathsIII(self, grid):
        rows = len(grid)
        cols = len(grid[0])
        empty = 0
        sr = sc = 0
        for r in range(rows):
            for c in range(cols):
                if grid[r][c] == 0:
                    empty += 1
                elif grid[r][c] == 1:
                    sr, sc = r, c
        self.count = 0
        def dfs(r, c, remaining):
            if grid[r][c] == 2:
                if remaining == 0:
                    self.count += 1
                return
            tmp = grid[r][c]
            grid[r][c] = -1
            for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                nr, nc = r + dr, c + dc
                if 0 <= nr < rows and 0 <= nc < cols and grid[nr][nc] != -1:
                    dfs(nr, nc, remaining - 1)
            grid[r][c] = tmp
        dfs(sr, sc, empty + 1)
        return self.count

